mapper.select:
SELECT DISTINCT a.menu_id, a.parent_id, a.menu_name, a.menu_system, a.perms, a.path, a.component, a.menu_type, a.is_frame, a.is_cache, a.icon, a.status, a.visible, a.order_num, a.remark FROM sys_menu a
JOIN sys_role_menu b ON a.menu_id=b.menu_id AND b.is_deleted=0 JOIN sys_role_user c ON b.role_id=c.role_id AND c.is_deleted=0
WHERE a.is_deleted=0 AND a.status=0
AND c.user_id=#{userId}
AND a.menu_system=#{type}
ORDER BY a.order_num ASC

SELECT a.menu_id, a.parent_id, a.menu_name, a.menu_system, a.perms, a.path, a.component, a.menu_type, a.is_frame, a.is_cache, a.icon, a.status, a.visible, a.order_num, a.remark FROM sys_menu a
JOIN sys_role_menu b ON a.menu_id=b.menu_id AND b.is_deleted=0 JOIN sys_role_user c ON b.role_id=c.role_id AND c.is_deleted=0
WHERE a.is_deleted=0 AND a.status=0
AND c.user_id=#{userId}
AND a.menu_system=#{type}
AND a.menu_type != 'B' GROUP BY a.menu_id, a.parent_id, a.menu_name, a.menu_system, a.perms, a.path, a.component, a.menu_type, a.is_frame, a.is_cache, a.icon, a.status, a.visible, a.order_num, a.remark ORDER BY order_num ASC
